update recipes set recipe_kind='cooked', instructions='{"reheat": "Reheat gently; eggs are best fresh.", "storage": "Keeps up to 1 day refrigerated.", "sections": [{"steps": [{"n": 1, "temp": null, "text": "Dice the tomatoes and saute in olive oil with the italian seasoning until softened, about 3 minutes.", "type": "cook", "active": true, "appliance": "stovetop", "duration_min": 3, "ingredient_refs": ["tomatoes, raw", "olive oil", "italian seasoning"]}, {"n": 2, "temp": null, "text": "Whisk the eggs, pour in, and softly scramble; crumble in the feta and season with sea salt.", "type": "cook", "active": true, "appliance": "stovetop", "duration_min": 5, "ingredient_refs": ["egg, whole, raw", "feta cheese", "sea salt"]}], "title": "Cook"}], "make_ahead": "Best cooked fresh.", "cook_time_min": 8, "prep_time_min": 4, "total_time_min": 12, "yield_servings": 1}'::jsonb where id='c215f022-e60a-4cc9-9975-e3ffafe1995a' and user_id is null;

