-- Mediterranean Shakshuka Style Eggs
update recipes set recipe_kind='cooked', instructions='{"reheat": "Reheat the sauce and poach fresh eggs.", "storage": "Store the sauce up to 3 days refrigerated.", "sections": [{"steps": [{"n": 1, "temp": null, "text": "Dice the onion and bell peppers and saute in olive oil until soft, about 5 minutes; stir in the cumin and paprika.", "type": "cook", "active": true, "appliance": "stovetop", "duration_min": 5, "ingredient_refs": ["onions, raw", "bell peppers, raw", "olive oil", "cumin, ground", "paprika"]}, {"n": 2, "temp": null, "text": "Add the diced tomatoes and simmer into a thick sauce, about 8 minutes; season with sea salt.", "type": "cook", "active": false, "appliance": "stovetop", "duration_min": 8, "ingredient_refs": ["tomato products, canned, diced", "sea salt"]}], "title": "Build the sauce"}, {"steps": [{"n": 3, "temp": null, "text": "Make wells in the sauce, crack in the eggs, cover, and cook until the whites set, about 6 minutes.", "type": "cook", "active": false, "appliance": "stovetop", "duration_min": 6, "ingredient_refs": ["egg, whole, raw"]}], "title": "Poach the eggs"}], "make_ahead": "Make the sauce up to 3 days ahead; poach the eggs fresh.", "cook_time_min": 19, "prep_time_min": 6, "total_time_min": 25, "yield_servings": 1}'::jsonb where id='3a3dd3f4-2808-4a8c-bc68-b51302f89245' and user_id is null;

